         overflow: hidden;
         text-overflow: ellipsis;
     }

 @media (max-width: 640.98px) {
     .top-row {
         justify-content: space-between;
     }

     .top-row ::deep a, .top-row ::deep .btn-link {
         margin-left: 0;
     }
 }

