namespace sv_810769f2baa140179dcb1aa57a62ca69.Services;

public class WarehouseInfo
{
    public string WarehouseId { get; set; } = "WH-001";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly Dictionary<string, string> AvailableWarehouses = new()
    {
        ["WH-001"] = "Warehouse A",
        ["WH-002"] = "Warehouse B",
        ["WH-003"] = "Warehouse C",
        ["WH-004"] = "Warehouse D"
    };
}

namespace sv_810769f2baa140179dcb1aa57a62ca69.Services;

/// <summary>
/// Scoped service that holds the current low-stock alert count for the active warehouse.
/// Components subscribe to <see cref="OnChange"/> and call
/// <see cref="RefreshAsync"/> to trigger a new simulated query.
/// Scoped lifetime ensures each user circuit has independent state.
/// </summary>
public class InventoryAlertService
{
