@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private CancellationTokenSource? _cts;
    private Action? _handler;
    private bool _isPolling;

    private string _alertCardClass =>
        AlertService.LowStockCount > 10 ? "border-danger" :
        AlertService.LowStockCount > 0 ? "border-warning" : "";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the warehouse changes.
        await StopPollingAsync();
        if (Warehouse is not null)
        {
            await AlertService.RefreshAsync(Warehouse.WarehouseId);
            StartPolling(Warehouse.WarehouseId);
        }
    }

    private void StartPolling(string warehouseId)
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(warehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on disposal or warehouse change.
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _isPolling = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_handler is not null)
        {
            AlertService.OnChange -= _handler;
        }
        await StopPollingAsync();
    }
}

