@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_810769f2baa140179dcb1aa57a62ca69.Services

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@_selectedId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseInfo.AvailableWarehouses)
        {
            <option value="@wh.Key">@wh.Value</option>
        }
    </select>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _selectedId = "WH-001";

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
        {
            _selectedId = Warehouse.WarehouseId;
        }
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "WH-001";
        if (WarehouseInfo.AvailableWarehouses.TryGetValue(newId, out var name))
        {
            var updated = new WarehouseInfo { WarehouseId = newId, WarehouseName = name };
            await WarehouseSource.NotifyChangedAsync(updated);
        }
    }
}

