@page "/dashboard"
@rendermode InteractiveServer
@using sv_810769f2baa140179dcb1aa57a62ca69.Services
@inject InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Current Warehouse</h5>
                <p class="display-6">@(Warehouse?.WarehouseName ?? "None")</p>
                <small class="text-muted">@(Warehouse?.WarehouseId)</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(_alertCardClass)">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Low Stock Alerts</h5>
                <p class="display-4 fw-bold">@AlertService.LowStockCount</p>
                <small class="text-muted">Items below minimum level</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Polling Status</h5>
                <p class="display-6">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-secondary">○ Stopped</span>
                    }
                </p>
                <small class="text-muted">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@if (AlertService.LowStockCount > 0)
{
    <div class="alert alert-warning mt-4" role="alert">
        <strong>⚠ Attention:</strong> There are <strong>@AlertService.LowStockCount</strong> items
        below minimum stock levels in <strong>@(Warehouse?.WarehouseName ?? "the selected warehouse")</strong>.
        Please review and reorder.
    </div>
}

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private CancellationTokenSource? _cts;
    private Action? _handler;
    private bool _isPolling;

    private string _alertCardClass =>
        AlertService.LowStockCount > 10 ? "border-danger" :
        AlertService.LowStockCount > 0 ? "border-warning" : "";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the warehouse changes.
        await StopPollingAsync();
        if (Warehouse is not null)
        {
            await AlertService.RefreshAsync(Warehouse.WarehouseId);
            StartPolling(Warehouse.WarehouseId);
        }
    }

    private void StartPolling(string warehouseId)
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(warehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on disposal or warehouse change.
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _isPolling = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_handler is not null)
        {
            AlertService.OnChange -= _handler;
        }
        await StopPollingAsync();
    }
}

