using Microsoft.AspNetCore.Components;
using sv_810769f2baa140179dcb1aa57a62ca69.Components;
using sv_810769f2baa140179dcb1aa57a62ca69.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Warehouse selection — CascadingValueSource crosses the static-layout / interactive-page boundary.
builder.Services.AddCascadingValue(sp =>
{
    var initial = new WarehouseInfo();
    return new CascadingValueSource<WarehouseInfo>(initial, isFixed: false);
});

// Per-circuit alert service — scoped so each user has independent state.
builder.Services.AddScoped<InventoryAlertService>();

